pub fn get_image_by_name(conn, profile_id, filename, album_id: Option<i64>) -> Option<ImageRecord> {
    match album_id {
        None => {
            // 根目录图片
            conn.query_row(
                "SELECT ... WHERE profile_id = ?1 AND filename = ?2 AND album_id IS NULL",
                ...
            ).ok()
        }
        Some(aid) => {
            conn.query_row(
                "SELECT ... WHERE profile_id = ?1 AND filename = ?2 AND album_id = ?3",
                params![profile_id, filename, aid],
                ...
            ).ok()
        }
    }
}
```

